from datetime import date, timedelta

# --- Find the earliest Friday the 13th from 0001-01-01 (proleptic Gregorian) ---
d = date(1, 1, 13)  # start checking the 13th of each month
earliest = None
while d.year < 2:  # search within year 1 first, extend if needed
    if d.weekday() == 4:  # Friday
        earliest = d
        break
    # jump to the 13th of the next month
    if d.month == 12:
        d = date(d.year + 1, 1, 13)
    else:
        d = date(d.year, d.month + 1, 13)

if not earliest:
    # widen search (shouldn't be needed)
    for yr in range(2, 100):
        for mo in range(1, 13):
            d = date(yr, mo, 13)
            if d.weekday() == 4:
                earliest = d
                break
        if earliest:
            break

print(f"Earliest Friday the 13th: {earliest}  (weekday check: {earliest.strftime('%A')})")

# --- Count Friday the 13ths in a full 400-year cycle (years 1–400) ---
count = 0
for yr in range(1, 401):
    for mo in range(1, 13):
        if date(yr, mo, 13).weekday() == 4:
            count += 1

print(f"Friday the 13ths in a 400-year cycle: {count}")
print(f"Average per year: {count / 400:.4f}")

# --- Bonus: distribution by month across the 400-year cycle ---
from collections import Counter
by_month = Counter()
for yr in range(1, 401):
    for mo in range(1, 13):
        if date(yr, mo, 13).weekday() == 4:
            by_month[mo] += 1

import calendar
print("\nDistribution by month:")
for mo in range(1, 13):
    print(f"  {calendar.month_abbr[mo]:>3}: {by_month[mo]}")
EOF

